5.query:
fetch dt.system.events
| filter dt.app.id == "dynatrace.launcher"
| parse resource, """LD "documents/" LD: launch.id"""
| lookup [ fetch dt.system.events, from: - 30d 
| filter isNotNull(user.email)
| summarize count(), by:{user.id, user.email}
], sourceField:user.id, lookupField:user.id
| fieldsRename user.email = lookup.user.email
| filterOut isNull(launch.id) and isNull(launchpad.name)
| fieldsRename launchpad.name = launch.id
| filter matchesPhrase(launchpad.name, "onboarding-")
| filterOut matchesPhrase(launchpad.name, "metadata") OR matchesPhrase(launchpad.name, "content")
| fieldsAdd Launchpad = coalesce(
    if(matchesPhrase(launchpad.name, "onboarding-developers"), "Onboarding - Developers"),
    if(matchesPhrase(launchpad.name, "onboarding-dynatrace-administrators-4c9ae2bd01"), "Onboarding - Dynatrace Administrators"),
    if(matchesPhrase(launchpad.name, "onboarding-dynatrace-support-helpdesk-13fb9c7ad5"), "Onboarding - Dynatrace Support & Helpdesk"),
    if(matchesPhrase(launchpad.name, "onboarding-frontend-developer-mobile-89de3ac4f2"), "Onboarding - Frontend Developer (Mobile)"),
    if(matchesPhrase(launchpad.name, "onboarding-frontend-developer-web-b2e84d79c1"), "Onboarding - Frontend Developer (Web)"),
    if(matchesPhrase(launchpad.name, "onboarding-home-page-accelerate-your-dynatrace-journey-fa9137bd42"), "Onboarding Home Page - Accelerate Your Dynatrace Journey"),
    if(matchesPhrase(launchpad.name, "onboarding-infrastructure-engineer-18bcd54ea3"), "Onboarding - Infrastructure Engineer"),
    if(matchesPhrase(launchpad.name, "onboarding-operations-9ae84f1bd2"), "Onboarding - Operations"),
    if(matchesPhrase(launchpad.name, "onboarding-platform-engineers-2ad913c7e8"), "Onboarding - Platform Engineers"),
    if(matchesPhrase(launchpad.name, "onboarding-security-engineers-d91c2b8a45"), "Onboarding - Security Engineers"),
    if(matchesPhrase(launchpad.name, "onboarding-site-reliability-engineers-54c8f13b9e"), "Onboarding - Site Reliability Engineers"),
    launchpad.name
)
| fieldsRemove launchpad.name
| summarize count = count(), by:{Launchpad}
| limit 20

